import gurobipy as gp
from gurobipy import GRB

def solve_transportation_problem(Cities, Links, Products, Supply, Demand, ShipmentCost, Capacity, JointCapacity):
    # Create model
    model = gp.Model("MultiProductTransportation")

    # Create decision variables: x[i,j,p] = units of product p shipped from i to j
    x = model.addVars(
        [(i, j, p) for i, j in Links for p in Products],
        vtype=GRB.INTEGER,
        name="x"
    )

    # Set objective: minimize total shipping cost
    model.setObjective(
        gp.quicksum(ShipmentCost[i, j, p] * x[i, j, p] for i, j in Links for p in Products),
        GRB.MINIMIZE
    )

    # Add supply constraints
    for i in Cities:
        for p_idx, p in enumerate(Products):
            model.addConstr(
                gp.quicksum(x[i, j, p] for j in Cities if (i, j) in Links) <= Supply[Cities.index(i)][p_idx],
                name=f"Supply_{i}_{p}"
            )

    # Add demand constraints
    for j in Cities:
        for p_idx, p in enumerate(Products):
            model.addConstr(
                gp.quicksum(x[i, j, p] for i in Cities if (i, j) in Links) >= Demand[Cities.index(j)][p_idx],
                name=f"Demand_{j}_{p}"
            )

    # Add product capacity constraints
    for i, j in Links:
        for p in Products:
            model.addConstr(
                x[i, j, p] <= Capacity[i, j, p],
                name=f"ProdCapacity_{i}_{j}_{p}"
            )

    # Add joint capacity constraints
    for i, j in Links:
        model.addConstr(
            gp.quicksum(x[i, j, p] for p in Products) <= JointCapacity[i, j],
            name=f"JointCapacity_{i}_{j}"
        )

    # Solve the model
    model.optimize()

    # Return results
    if model.status == GRB.OPTIMAL:
        total_cost = model.objVal
        shipment_plan = []
        for i, j, p in x.keys():
            if x[i, j, p].x > 0:
                shipment_plan.append((i, j, p, x[i, j, p].x))
        return total_cost, shipment_plan
    else:
        return None, None

# Example usage with the provided data
if __name__ == "__main__":
    # Input data
    Cities = ["A", "B"]
    Links = [("A", "B")]
    Products = ["Product1"]
    Supply = [[10], [0]]  # Supply[i][p] for city i and product p
    Demand = [[0], [10]]  # Demand[i][p] for city i and product p

    # Convert to dictionary format for clarity
    ShipmentCost = {("A", "B", "Product1"): 1}
    Capacity = {("A", "B", "Product1"): 10}
    JointCapacity = {("A", "B"): 10}

    # Solve the problem
    total_cost, shipment_plan = solve_transportation_problem(
        Cities, Links, Products, Supply, Demand, 
        ShipmentCost, Capacity, JointCapacity
    )

    # Output results
    if total_cost is not None:
        print(f"Optimal solution found. Total cost: {total_cost}")
        print("Shipping plan:")
        for i, j, p, units in shipment_plan:
            print(f"Ship {units} units of {p} from {i} to {j}")
    else:
        print("No optimal solution found.")

from gurobipy import *

# Data
patients = ['A', 'B', 'C']
devices = ['A', 'B', 'C']

# Tests for each patient: (device, duration)
tests = {
    'A': [('B', 2), ('A', 2), ('C', 6)],
    'B': [('B', 7), ('A', 6), ('C', 10)],
    'C': [('C', 8), ('A', 9), ('B', 5)]
}

# Create model
model = Model("HospitalScheduling")

# Decision variables
start = {}
end = {}
for p in patients:
    for i in range(len(tests[p])):
        start[p, i] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"start_{p}_{i}")
        end[p, i] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"end_{p}_{i}")

# Makespan
makespan = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name="makespan")

# Binary variables for device conflicts
y = {}
for p1 in patients:
    for i1 in range(len(tests[p1])):
        d1 = tests[p1][i1][0]
        for p2 in patients:
            for i2 in range(len(tests[p2])):
                d2 = tests[p2][i2][0]
                if (p1 != p2 or i1 != i2) and d1 == d2:
                    y[p1, i1, p2, i2] = model.addVar(vtype=GRB.BINARY, name=f"y_{p1}_{i1}_{p2}_{i2}")

model.update()

# Big M (sum of all durations)
M = sum(duration for p in patients for (_, duration) in tests[p])

# Constraints
# Test sequence constraints
for p in patients:
    for i in range(1, len(tests[p])):
        model.addConstr(start[p, i] >= end[p, i-1], f"sequence_{p}_{i}")

# Device capacity constraints
for p1 in patients:
    for i1 in range(len(tests[p1])):
        d1 = tests[p1][i1][0]
        for p2 in patients:
            for i2 in range(len(tests[p2])):
                d2 = tests[p2][i2][0]
                if (p1 != p2 or i1 != i2) and d1 == d2:
                    model.addConstr(
                        start[p1, i1] >= end[p2, i2] - M * (1 - y[p1, i1, p2, i2]),
                        f"device_conflict1_{p1}_{i1}_{p2}_{i2}"
                    )
                    model.addConstr(
                        start[p2, i2] >= end[p1, i1] - M * y[p1, i1, p2, i2],
                        f"device_conflict2_{p1}_{i1}_{p2}_{i2}"
                    )

# Duration constraints
for p in patients:
    for i in range(len(tests[p])):
        model.addConstr(
            end[p, i] == start[p, i] + tests[p][i][1],
            f"duration_{p}_{i}"
        )

# Makespan definition
for p in patients:
    for i in range(len(tests[p])):
        model.addConstr(makespan >= end[p, i], f"makespan_{p}_{i}")

# Objective
model.setObjective(makespan, GRB.MINIMIZE)

# Solve
model.optimize()

# Print solution
if model.status == GRB.OPTIMAL:
    print(f"Optimal makespan: {model.objVal}")
    for p in patients:
        for i in range(len(tests[p])):
            print(f"Patient {p}, Test {i+1} ({tests[p][i][0]}): starts at {start[p, i].X}, ends at {end[p, i].X}")
else:
    print("No solution found")

from gurobipy import Model, GRB

# Create model
model = Model("HospitalScheduling")

# Data
patients = ['A', 'B', 'C']
tests = [1, 2, 3]
devices = ['A', 'B', 'C']

# Device and duration for each patient's tests
patient_data = {
    'A': [('C', 2), ('A', 4), ('B', 10)],
    'B': [('C', 2), ('A', 6), ('B', 2)],
    'C': [('A', 3), ('C', 2), ('B', 8)]
}

# Decision variables
start = {}
end = {}
for p in patients:
    for t in tests:
        start[p, t] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"start_{p}_{t}")
        end[p, t] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"end_{p}_{t}")

# Makespan
makespan = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name="makespan")

# Binary variables for device conflicts
y = {}
for p1 in patients:
    for t1 in tests:
        for p2 in patients:
            for t2 in tests:
                if (p1 != p2 or t1 != t2) and patient_data[p1][t1-1][0] == patient_data[p2][t2-1][0]:
                    y[p1, t1, p2, t2] = model.addVar(vtype=GRB.BINARY, name=f"y_{p1}_{t1}_{p2}_{t2}")

# Big M (sum of all durations)
M = sum(patient_data[p][t-1][1] for p in patients for t in tests)

# Objective: minimize makespan
model.setObjective(makespan, GRB.MINIMIZE)

# Constraints
# Sequence constraints
for p in patients:
    for t in range(2, 4):
        model.addConstr(start[p, t] >= end[p, t-1], f"seq_{p}_{t}")

# Device capacity constraints
for p1 in patients:
    for t1 in tests:
        for p2 in patients:
            for t2 in tests:
                if (p1 != p2 or t1 != t2) and patient_data[p1][t1-1][0] == patient_data[p2][t2-1][0]:
                    model.addConstr(
                        start[p1, t1] >= end[p2, t2] - M * (1 - y[p1, t1, p2, t2]),
                        f"device_conflict1_{p1}_{t1}_{p2}_{t2}"
                    )
                    model.addConstr(
                        start[p2, t2] >= end[p1, t1] - M * y[p1, t1, p2, t2],
                        f"device_conflict2_{p1}_{t1}_{p2}_{t2}"
                    )

# End time definition
for p in patients:
    for t in tests:
        model.addConstr(
            end[p, t] == start[p, t] + patient_data[p][t-1][1],
            f"end_def_{p}_{t}"
        )

# Makespan definition
for p in patients:
    for t in tests:
        model.addConstr(
            makespan >= end[p, t],
            f"makespan_def_{p}_{t}"
        )

# Solve
model.optimize()

# Print solution
if model.status == GRB.OPTIMAL:
    print(f"Optimal makespan: {model.objVal}")
    for p in patients:
        for t in tests:
            print(f"Patient {p}, Test {t}: starts at {start[p, t].X}, ends at {end[p, t].X}")
else:
    print("No solution found")

import gurobipy as gp
from gurobipy import GRB

# Create a new model
model = gp.Model("PortScheduling")

# Shipments and their routes
shipments = {
    'S1': [('A', 9), ('C', 8), ('B', 2)],
    'S2': [('B', 9), ('C', 6), ('A', 9)],
    'S3': [('A', 2), ('B', 10), ('C', 7)]
}

# Extract all operations and ports
operations = {}
ports = set()
for s in shipments:
    operations[s] = []
    for idx, (port, time) in enumerate(shipments[s]):
        operations[s].append((f"{s}_o{idx+1}", port, time))
        ports.add(port)
ports = list(ports)

# Big M (sum of all handling times)
M = sum(time for s in shipments for (_, time) in shipments[s])

# Decision variables
start = {}
end = {}
for s in operations:
    for op in operations[s]:
        op_name, _, _ = op
        start[op_name] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"start_{op_name}")
        end[op_name] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"end_{op_name}")

# Binary variables for port sequencing
y = {}
for s1 in operations:
    for op1 in operations[s1]:
        op1_name, port1, _ = op1
        for s2 in operations:
            for op2 in operations[s2]:
                op2_name, port2, _ = op2
                if (s1 != s2 or op1_name != op2_name) and port1 == port2:
                    y[(op1_name, op2_name)] = model.addVar(vtype=GRB.BINARY, name=f"y_{op1_name}_{op2_name}")

# Makespan variable
makespan = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name="makespan")

# Constraints
# Operation sequence for each shipment
for s in operations:
    for i in range(len(operations[s]) - 1):
        op1_name, _, _ = operations[s][i]
        op2_name, _, _ = operations[s][i+1]
        model.addConstr(start[op2_name] >= end[op1_name], f"seq_{s}_{op1_name}_{op2_name}")

# Port capacity constraints
for s1 in operations:
    for op1 in operations[s1]:
        op1_name, port1, _ = op1
        for s2 in operations:
            for op2 in operations[s2]:
                op2_name, port2, _ = op2
                if (s1 != s2 or op1_name != op2_name) and port1 == port2:
                    model.addConstr(
                        start[op1_name] >= end[op2_name] - M * (1 - y[(op1_name, op2_name)]),
                        f"port_cap_{op1_name}_{op2_name}_1"
                    )
                    model.addConstr(
                        start[op2_name] >= end[op1_name] - M * y[(op1_name, op2_name)],
                        f"port_cap_{op1_name}_{op2_name}_2"
                    )

# End time calculation
for s in operations:
    for op in operations[s]:
        op_name, _, time = op
        model.addConstr(end[op_name] == start[op_name] + time, f"end_{op_name}")

# Makespan definition
for s in operations:
    for op in operations[s]:
        op_name, _, _ = op
        model.addConstr(makespan >= end[op_name], f"makespan_{op_name}")

# Objective: minimize makespan
model.setObjective(makespan, GRB.MINIMIZE)

# Solve the model
model.optimize()

# Print the solution
if model.status == GRB.OPTIMAL:
    print(f"Optimal makespan: {makespan.X}")
    print("Schedule:")
    for s in operations:
        print(f"Shipment {s}:")
        for op in operations[s]:
            op_name, port, _ = op
            print(f"  {op_name}: Port {port}, Start {start[op_name].X}, End {end[op_name].X}")
else:
    print("No optimal solution found.")

import gurobipy as gp
from gurobipy import GRB

# Create model
model = gp.Model("ShipmentScheduling")

# Shipment sequences: {shipment: [(hub, duration), ...]}
shipments = {
    "S1": [("B", 3), ("A", 4), ("C", 3)],
    "S2": [("A", 2), ("B", 2), ("C", 3)],
    "S3": [("A", 9), ("C", 7), ("B", 9)]
}

# Extract all operations and hubs
operations = {}
hubs = set()
for s in shipments:
    operations[s] = list(range(len(shipments[s])))
    for o in operations[s]:
        hubs.add(shipments[s][o][0])
hubs = list(hubs)

# Big M (sum of all durations)
M = sum(d for s in shipments for (_, d) in shipments[s])

# Decision variables
start = {}
end = {}
for s in shipments:
    for o in operations[s]:
        start[s, o] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"start_{s}_{o}")
        end[s, o] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"end_{s}_{o}")

# Binary variables for sequencing at hubs
y = {}
for s1 in shipments:
    for o1 in operations[s1]:
        hub1 = shipments[s1][o1][0]
        for s2 in shipments:
            for o2 in operations[s2]:
                hub2 = shipments[s2][o2][0]
                if hub1 == hub2 and (s1, o1) != (s2, o2):
                    y[s1, o1, s2, o2] = model.addVar(vtype=GRB.BINARY, name=f"y_{s1}_{o1}_{s2}_{o2}")

# Makespan variable
makespan = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name="makespan")

# Constraints
# Sequence constraints
for s in shipments:
    for o in range(len(operations[s]) - 1):
        model.addConstr(start[s, o+1] >= end[s, o], f"seq_{s}_{o}")

# Hub capacity constraints
for s1 in shipments:
    for o1 in operations[s1]:
        hub1 = shipments[s1][o1][0]
        for s2 in shipments:
            for o2 in operations[s2]:
                hub2 = shipments[s2][o2][0]
                if hub1 == hub2 and (s1, o1) != (s2, o2):
                    model.addConstr(
                        start[s1, o1] >= end[s2, o2] - M * (1 - y[s1, o1, s2, o2]),
                        f"hub_cap_{s1}_{o1}_{s2}_{o2}_1"
                    )
                    model.addConstr(
                        start[s2, o2] >= end[s1, o1] - M * y[s1, o1, s2, o2],
                        f"hub_cap_{s1}_{o1}_{s2}_{o2}_2"
                    )

# Duration constraints
for s in shipments:
    for o in operations[s]:
        model.addConstr(
            end[s, o] == start[s, o] + shipments[s][o][1],
            f"duration_{s}_{o}"
        )

# Makespan constraints
for s in shipments:
    for o in operations[s]:
        model.addConstr(makespan >= end[s, o], f"makespan_{s}_{o}")

# Objective
model.setObjective(makespan, GRB.MINIMIZE)

# Solve
model.optimize()

# Print solution
if model.status == GRB.OPTIMAL:
    print(f"Optimal makespan: {makespan.X}")
    for s in shipments:
        for o in operations[s]:
            print(f"{s} operation {o} (hub {shipments[s][o][0]}): starts at {start[s, o].X}, ends at {end[s, o].X}")
else:
    print("No solution found")

from gurobipy import Model, GRB

# Create model
m = Model("HospitalScheduling")

# Data
patients = ['A', 'B', 'C']
rooms = ['Room1', 'Room2', 'Room3']

# Procedures for each patient: (room, duration)
procedures = {
    'A': [('Room1', 2), ('Room3', 4), ('Room2', 6)],
    'B': [('Room1', 1), ('Room2', 2), ('Room3', 3)],
    'C': [('Room3', 10), ('Room1', 9), ('Room2', 10)]
}

# Extract all (patient, procedure) pairs
patient_procedures = []
for p in patients:
    for s in range(len(procedures[p])):
        patient_procedures.append((p, s))

# Decision variables
start = m.addVars(patient_procedures, name="start")
end = m.addVars(patient_procedures, name="end")
makespan = m.addVar(name="makespan")

# Binary variables for room conflicts
y = m.addVars(patient_procedures, patient_procedures, vtype=GRB.BINARY, name="y")

# Large constant
M = sum(duration for p in patients for (room, duration) in procedures[p])

# Constraints
# 1. Procedure sequence for each patient
for p in patients:
    for s in range(len(procedures[p]) - 1):
        m.addConstr(start[p, s+1] >= end[p, s], f"sequence_{p}_{s}")

# 2. Room capacity
for (p, s) in patient_procedures:
    for (p_prime, s_prime) in patient_procedures:
        if (p, s) != (p_prime, s_prime):
            room_p_s = procedures[p][s][0]
            room_p_prime_s_prime = procedures[p_prime][s_prime][0]
            if room_p_s == room_p_prime_s_prime:
                m.addConstr(
                    start[p_prime, s_prime] >= end[p, s] - M * (1 - y[p, s, p_prime, s_prime]),
                    f"room_conflict1_{p}_{s}_{p_prime}_{s_prime}"
                )
                m.addConstr(
                    start[p, s] >= end[p_prime, s_prime] - M * y[p, s, p_prime, s_prime],
                    f"room_conflict2_{p}_{s}_{p_prime}_{s_prime}"
                )

# 3. End time calculation
for (p, s) in patient_procedures:
    m.addConstr(
        end[p, s] == start[p, s] + procedures[p][s][1],
        f"end_time_{p}_{s}"
    )

# 4. Makespan definition
for p in patients:
    last_procedure = len(procedures[p]) - 1
    m.addConstr(
        makespan >= end[p, last_procedure],
        f"makespan_{p}"
    )

# Objective
m.setObjective(makespan, GRB.MINIMIZE)

# Solve
m.optimize()

# Print solution
if m.status == GRB.OPTIMAL:
    print(f"Optimal makespan: {makespan.X}")
    for (p, s) in patient_procedures:
        print(f"Patient {p}, Procedure {s}: starts at {start[p, s].X}, ends at {end[p, s].X}")
else:
    print("No solution found")

from gurobipy import Model, GRB

# Create model
m = Model("Vessel_Scheduling")

# Data
vessels = {
    "Alpha": [("A", 4), ("C", 5), ("B", 6)],
    "Beta": [("C", 4), ("B", 1), ("A", 3)],
    "Bravo": [("A", 2), ("B", 10), ("C", 8)]
}

# Extract all terminals
terminals = set()
for v in vessels:
    for (t, _) in vessels[v]:
        terminals.add(t)
terminals = list(terminals)

# Steps for each vessel (1-indexed)
steps = {v: list(range(1, len(vessels[v]) + 1)) for v in vessels}

# Big M (sum of all handling times)
M = sum(time for v in vessels for (_, time) in vessels[v])

# Decision variables
start = {}
end = {}
for v in vessels:
    for s in steps[v]:
        start[v, s] = m.addVar(lb=0, name=f"start_{v}_{s}")
        end[v, s] = m.addVar(lb=0, name=f"end_{v}_{s}")

# Makespan
makespan = m.addVar(lb=0, name="makespan")

# Binary variables for terminal conflicts
y = {}
for v1 in vessels:
    for s1 in steps[v1]:
        t1 = vessels[v1][s1 - 1][0]  # terminal for v1 at step s1
        for v2 in vessels:
            if v1 == v2:
                continue
            for s2 in steps[v2]:
                t2 = vessels[v2][s2 - 1][0]  # terminal for v2 at step s2
                if t1 == t2:
                    y[v1, s1, v2, s2] = m.addVar(vtype=GRB.BINARY, name=f"y_{v1}_{s1}_{v2}_{s2}")

# Objective: minimize makespan
m.setObjective(makespan, GRB.MINIMIZE)

# Constraints
for v in vessels:
    # Step order constraints
    for i in range(1, len(steps[v])):
        m.addConstr(start[v, i + 1] >= end[v, i], f"step_order_{v}_{i}")

    # Handling time constraints
    for s in steps[v]:
        m.addConstr(end[v, s] == start[v, s] + vessels[v][s - 1][1], f"handling_time_{v}_{s}")

# Terminal capacity constraints
for v1 in vessels:
    for s1 in steps[v1]:
        t1 = vessels[v1][s1 - 1][0]
        for v2 in vessels:
            if v1 == v2:
                continue
            for s2 in steps[v2]:
                t2 = vessels[v2][s2 - 1][0]
                if t1 == t2:
                    m.addConstr(
                        start[v2, s2] >= end[v1, s1] - M * (1 - y[v1, s1, v2, s2]),
                        f"terminal_capacity_1_{v1}_{s1}_{v2}_{s2}"
                    )
                    m.addConstr(
                        start[v1, s1] >= end[v2, s2] - M * y[v1, s1, v2, s2],
                        f"terminal_capacity_2_{v1}_{s1}_{v2}_{s2}"
                    )

# Makespan definition
for v in vessels:
    last_step = max(steps[v])
    m.addConstr(makespan >= end[v, last_step], f"makespan_{v}")

# Solve
m.optimize()

# Print solution
if m.status == GRB.OPTIMAL:
    print(f"Optimal makespan: {makespan.X}")
    for v in vessels:
        print(f"\nVessel {v}:")
        for s in steps[v]:
            t = vessels[v][s - 1][0]
            print(f"  Step {s} (Terminal {t}): Start at {start[v, s].X}, End at {end[v, s].X}")
else:
    print("No solution found")

import gurobipy as gp
from gurobipy import GRB

# Define the routes and their stages
routes = {
    'R1': [('C2', 3), ('C3', 5), ('C4', 1), ('C1', 1)],
    'R2': [('C1', 6), ('C4', 10), ('C2', 1), ('C3', 10)],
    'R3': [('C4', 6), ('C3', 9), ('C2', 3), ('C1', 4)],
    'R4': [('C4', 3), ('C3', 3), ('C2', 5), ('C1', 6)]
}

# Create a model
model = gp.Model("DeliveryRouteScheduling")

# Decision variables
start = {}
end = {}
y = {}

# Large constant for big-M constraints
M = sum(duration for route in routes.values() for (_, duration) in route)

# Add variables
for r in routes:
    for s in range(len(routes[r])):
        start[(r, s)] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"start_{r}_{s}")
        end[(r, s)] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"end_{r}_{s}")

# Add binary variables for disjunctive constraints
for r1 in routes:
    for s1 in range(len(routes[r1])):
