import gurobipy as gp
from gurobipy import GRB

# Create model
model = gp.Model("Port_Scheduling")

# Shipments and Ports
shipments = ['S1', 'S2', 'S3']
ports = ['A', 'B', 'C']

# Processing times: p[i][j][k] = processing time of shipment i at port j in operation k
p = {
    'S1': {'A': {1: 9}, 'C': {2: 8}, 'B': {3: 2}},
    'S2': {'B': {1: 9}, 'C': {2: 6}, 'A': {3: 9}},
    'S3': {'A': {1: 2}, 'B': {2: 10}, 'C': {3: 7}}
}

# Big-M (upper bound on makespan)
M = sum(p[i][j][k] for i in shipments for j in ports for k in p[i][j].keys())

# Decision variables
s = {}  # Start times
for i in shipments:
    for j in ports:
        for k in p[i].get(j, {}):
            s[(i, j, k)] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"s_{i}_{j}_{k}")

C_max = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name="C_max")

# Binary variables for port sequencing
y = {}
for j in ports:
    for i1 in shipments:
        for i2 in shipments:
            if i1 != i2 and j in p[i1] and j in p[i2]:
                y[(i1, i2, j)] = model.addVar(vtype=GRB.BINARY, name=f"y_{i1}_{i2}_{j}")

# Objective: minimize makespan
model.setObjective(C_max, GRB.MINIMIZE)

# Operation precedence constraints
for i in shipments:
    # S1: A(1) -> C(2) -> B(3)
    if i == 'S1':
        model.addConstr(s[('S1', 'A', 1)] + 9 <= s[('S1', 'C', 2)], "S1_A_before_C")
        model.addConstr(s[('S1', 'C', 2)] + 8 <= s[('S1', 'B', 3)], "S1_C_before_B")
    # S2: B(1) -> C(2) -> A(3)
    elif i == 'S2':
        model.addConstr(s[('S2', 'B', 1)] + 9 <= s[('S2', 'C', 2)], "S2_B_before_C")
        model.addConstr(s[('S2', 'C', 2)] + 6 <= s[('S2', 'A', 3)], "S2_C_before_A")
    # S3: A(1) -> B(2) -> C(3)
    elif i == 'S3':
        model.addConstr(s[('S3', 'A', 1)] + 2 <= s[('S3', 'B', 2)], "S3_A_before_B")
        model.addConstr(s[('S3', 'B', 2)] + 10 <= s[('S3', 'C', 3)], "S3_B_before_C")

# Port capacity constraints
for j in ports:
    # Get all shipments that use this port
    using_shipments = [i for i in shipments if j in p[i]]
    # Add sequencing constraints for each pair
    for idx1, i1 in enumerate(using_shipments):
        for idx2, i2 in enumerate(using_shipments):
            if idx1 < idx2:  # Avoid duplicate constraints
                k1 = next(iter(p[i1][j]))  # Get the operation number for i1 at j
                k2 = next(iter(p[i2][j]))  # Get the operation number for i2 at j
                model.addConstr(
                    s[(i1, j, k1)] + p[i1][j][k1] <= s[(i2, j, k2)] + M * (1 - y[(i1, i2, j)]),
                    f"port_{j}_seq_{i1}_before_{i2}"
                )
                model.addConstr(
                    s[(i2, j, k2)] + p[i2][j][k2] <= s[(i1, j, k1)] + M * y[(i1, i2, j)],
                    f"port_{j}_seq_{i2}_before_{i1}"
                )

# Makespan constraints
for i in shipments:
    for j in ports:
        for k in p[i].get(j, {}):
            model.addConstr(
                s[(i, j, k)] + p[i][j][k] <= C_max,
                f"makespan_{i}_{j}_{k}"
