start = model.addVars(shipments, steps, vtype=GRB.CONTINUOUS, name="start")
end = model.addVars(shipments, steps, vtype=GRB.CONTINUOUS, name="end")
makespan = model.addVar(vtype=GRB.CONTINUOUS, name="makespan")

# Binary variables for port sequencing
y = model.addVars(
    [(s, t, s_prime, t_prime) 
     for s in shipments for t in steps 
     for s_prime in shipments for t_prime in steps 
     if (s, t) != (s_prime, t_prime) and inspection_details[s][t-1][0] == inspection_details[s_prime][t_prime-1][0]],
