                        start[s, t] >= end[s_prime, t_prime] - M * (1 - y[s, t, s_prime, t_prime]),
                        f"port_capacity_1_{s}_{t}_{s_prime}_{t_prime}"
                    )
                    model.addConstr(
                        start[s_prime, t_prime] >= end[s, t] - M * y[s, t, s_prime, t_prime],
