start = {}
end = {}
for r in routes:
    for s in range(len(routes[r])):
        start[(r, s)] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"start_{r}_{s}")
        end[(r, s)] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"end_{r}_{s}")

# Binary variables for ordering at hubs
y = {}
hubs = set(h for r in routes.values() for (h, _) in r)
for h in hubs:
    steps = [(r, s) for r in routes for s in range(len(routes[r])) if routes[r][s][0] == h]
    for i in range(len(steps)):
        for j in range(i + 1, len(steps)):
            r1, s1 = steps[i]
            r2, s2 = steps[j]
            y[(r1, s1, r2, s2)] = model.addVar(vtype=GRB.BINARY, name=f"y_{r1}_{s1}_{r2}_{s2}")

# Makespan
makespan = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name="makespan")

