    steps = [(r, s) for r in routes for s in range(len(routes[r])) if routes[r][s][0] == h]
    for i in range(len(steps)):
        for j in range(i + 1, len(steps)):
            r1, s1 = steps[i]
            r2, s2 = steps[j]
            model.addConstr(
                start[(r2, s2)] >= end[(r1, s1)] - M * (1 - y[(r1, s1, r2, s2)]),
                f"hub_{h}_order_{r1}_{s1}_{r2}_{s2}_1"
