import gurobipy as gp
from gurobipy import GRB

# Define the problem data
trucks = {
    1: [(1, 1), (3, 10), (4, 6), (2, 1), (6, 6), (7, 3), (5, 6)],
    2: [(3, 6), (4, 3), (6, 1), (5, 8), (1, 9), (7, 3), (2, 7)],
