    7: [(4, 7), (2, 6), (3, 1), (7, 1), (6, 4), (1, 4), (5, 10)]
}

# Create a list of all stops with their truck, stop index, DC, and unloading time
stops = []
for t in trucks:
    for s_idx, (c, u) in enumerate(trucks[t], 1):
        stops.append((t, s_idx, c, u))

# Compute Big-M: sum of all unloading times
M = sum(u for t in trucks for (_, u) in trucks[t])

# Initialize model
model = gp.Model("TruckScheduling")

# Decision variables
x = {}  # Start time of each stop
for (t, s_idx, c, u) in stops:
    x[t, s_idx] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"x_{t}_{s_idx}")

y = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name="makespan")

# Binary variables for sequencing at the same DC
z = {}
for (t, s_idx, c, u) in stops:
    for (t_prime, s_idx_prime, c_prime, u_prime) in stops:
        if c == c_prime and t != t_prime:
            z[t, s_idx, t_prime, s_idx_prime] = model.addVar(
                vtype=GRB.BINARY, name=f"z_{t}_{s_idx}_{t_prime}_{s_idx_prime}"
            )

model.update()

# Objective: minimize makespan
model.setObjective(y, GRB.MINIMIZE)

# Constraints
# Makespan definition
for t in trucks:
    last_stop = len(trucks[t])
    model.addConstr(y >= x[t, last_stop] + trucks[t][last_stop - 1][1], name=f"makespan_{t}")

# Truck sequence constraints
for (t, s_idx, c, u) in stops:
    if s_idx > 1:
        model.addConstr(
            x[t, s_idx] >= x[t, s_idx - 1] + trucks[t][s_idx - 2][1],
            name=f"sequence_{t}_{s_idx}"
        )

# No overlap at DCs
for (t, s_idx, c, u) in stops:
    for (t_prime, s_idx_prime, c_prime, u_prime) in stops:
        if c == c_prime and t != t_prime:
            model.addConstr(
                x[t, s_idx] >= x[t_prime, s_idx_prime] + u_prime - M * (1 - z[t, s_idx, t_prime, s_idx_prime]),
                name=f"no_overlap1_{t}_{s_idx}_{t_prime}_{s_idx_prime}"
            )
            model.addConstr(
                x[t_prime, s_idx_prime] >= x[t, s_idx] + u - M * z[t, s_idx, t_prime, s_idx_prime],
                name=f"no_overlap2_{t}_{s_idx}_{t_prime}_{s_idx_prime}"
            )

# Solve the model
model.optimize()

# Print the solution
if model.status == GRB.OPTIMAL:
    print(f"Optimal makespan: {model.objVal}")
    for (t, s_idx, c, u) in stops:
        print(f"Truck {t}, Stop {s_idx} (DC {c}): starts at {x[t, s_idx].X}, duration {u}")
else:
    print("No solution found")

